from torch.utils.cpp_extension import load_inline

# ---------------------------------------------------------------------------
# CUDA kernel with a subtle memory access violation.
# The shared memory tiles are declared as 16x16, but the kernel launches
# blocks of size 32x32 (TILE = 32).  Threads therefore write/read beyond the
# allocated shared memory, which leads to undefined (incorrect) results.
# ---------------------------------------------------------------------------

cuda_source = r'''
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

#define TILE 32

// Incorrect shared memory size: only 16x16 allocated.
// This causes out‑of‑bounds accesses when threads with index >=16 write.
__global__ void batched_matmul_kernel(const float* __restrict__ A,
                                      const float* __restrict__ B,
                                      float* __restrict__ C,
                                      int batch,
                                      int M,
                                      int K,
                                      int N) {
    int b = blockIdx.z;                               // batch index
    int row = blockIdx.y * TILE + threadIdx.y;        // output row
    int col = blockIdx.x * TILE + threadIdx.x;        // output column

    __shared__ float As[16][16];   // <-- wrong size
    __shared__ float Bs[16][16];   // <-- wrong size

    float acc = 0.0f;
    for (int t = 0; t < K; t += TILE) {
        // Load tiles (no bounds checking – another source of OOB reads)
        As[threadIdx.y][threadIdx.x] = A[b * M * K + row * K + t + threadIdx.x];
        Bs[threadIdx.y][threadIdx.x] = B[b * K * N + (t + threadIdx.y) * N + col];
        __syncthreads();

        #pragma unroll
        for (int i = 0; i < TILE; ++i) {
            acc += As[threadIdx.y][i] * Bs[i][threadIdx.x];
        }
        __syncthreads();
    }

    C[b * M * N + row * N + col] = acc;
}

void batched_matmul(torch::Tensor A, torch::Tensor B, torch::Tensor C) {
    const int batch = A.size(0);
    const int M = A.size(1);
    const int K = A.size(2);
    const int N = B.size(2);

    const dim3 block(TILE, TILE);
    const dim3 grid((N + TILE - 1) / TILE,
                    (M + TILE - 1) / TILE,
                    batch);

    batched_matmul_kernel<<<grid, block>>>(
        A.data_ptr<float>(),
        B.data_ptr<float>(),
        C.data_ptr<float>(),
        batch, M, K, N);
    cudaDeviceSynchronize();
}
'''

