extern "C"
__global__ void mean_reduce(const float* __restrict__ input, float* __restrict__ output, int N) {
    // Single thread does the whole reduction (for simplicity).
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        float sum = 0.0f;
        // Off‑by‑one error: loops one step too far.
        for (int i = 0; i <= N; ++i) {
            sum += input[i];
        }
        output[0] = sum / static_cast<float>(N);
